app = Flask(__name__)

MONGO_URI = os.getenv("MONGO_URI", "mongodb://localhost:27017")
DB_NAME = os.getenv("MONGO_DB", "cms_db")

client = MongoClient(MONGO_URI)
db = client[DB_NAME]
users_col = db["users"]
documents_col = db["documents"]

users_col.create_index([("email", ASCENDING)], unique=True)
documents_col.create_index([("author_id", ASCENDING)])
documents_col.create_index([("tags", ASCENDING)])
documents_col.create_index([("created_at", ASCENDING)])


def serialize_doc(doc):
    if not doc:
        return None
    doc["_id"] = str(doc["_id"])
    if "author_id" in doc and isinstance(doc["author_id"], ObjectId):
        doc["author_id"] = str(doc["author_id"])
    if "created_at" in doc and isinstance(doc["created_at"], datetime):
        doc["created_at"] = doc["created_at"].isoformat()
    if "updated_at" in doc and isinstance(doc["updated_at"], datetime):
        doc["updated_at"] = doc["updated_at"].isoformat()
    return doc


def parse_object_id(value):
    try:
        return ObjectId(value)
    except Exception:
        return None


