@app.route("/documents", methods=["GET"])
def query_documents():
    author_id = request.args.get("author_id")
    tag = request.args.get("tag")
    status = request.args.get("status")
    text = request.args.get("q")
    limit = min(int(request.args.get("limit", 20)), 100)
    skip = max(int(request.args.get("skip", 0)), 0)

    query = {}
    if author_id:
        author_oid = parse_object_id(author_id)
        if not author_oid:
            return jsonify({"error": "invalid_author_id"}), 400
        query["author_id"] = author_oid
    if tag:
        query["tags"] = tag
    if status:
        query["status"] = status
    if text:
        query["$or"] = [
            {"title": {"$regex": text, "$options": "i"}},
            {"content": {"$regex": text, "$options": "i"}},
        ]

    cursor = documents_col.find(query).sort("created_at", -1).skip(skip).limit(limit)
    documents = [serialize_doc(d) for d in cursor]
    return jsonify({"documents": documents, "count": len(documents)}), 200


